// src/pages/ProgressPage.js
import React, { useEffect, useState } from "react";
import { getSessions } from "../utils/firebase";
import "./ProgressPage.css";

function ScoreCircle({ score }) {
  const s = Number(score) || 0;
  const r = 48;
  const circ = 2 * Math.PI * r;
  const dash = (s / 100) * circ;

  return (
    <div className="progress-score-circle">
      <svg width="126" height="126" viewBox="0 0 126 126">
        <circle
          cx="63"
          cy="63"
          r={r}
          fill="none"
          stroke="#ede9ff"
          strokeWidth="11"
        />
        <circle
          cx="63"
          cy="63"
          r={r}
          fill="none"
          stroke="#7c6fcd"
          strokeWidth="11"
          strokeDasharray={`${dash} ${circ}`}
          strokeLinecap="round"
          transform="rotate(-90 63 63)"
        />
      </svg>

      <div className="progress-score-text">
        <span>{s}</span>
        <small>/100</small>
      </div>
    </div>
  );
}

function StatCard({ label, value, sub, icon, color = "#7c6fcd" }) {
  return (
    <div className="progress-stat-card">
      <div className="progress-stat-icon" style={{ color }}>
        {icon}
      </div>
      <div className="progress-stat-value" style={{ color }}>
        {value}
      </div>
      <div className="progress-stat-label">{label}</div>
      {sub && <div className="progress-stat-sub">{sub}</div>}
    </div>
  );
}

function ProgressBar({ label, value, color = "#7c6fcd" }) {
  const v = Math.max(0, Math.min(100, Number(value) || 0));

  return (
    <div className="progress-bar-item">
      <div className="progress-bar-top">
        <span>{label}</span>
        <b style={{ color }}>{v}</b>
      </div>
      <div className="progress-bar-track">
        <div
          className="progress-bar-fill"
          style={{
            width: `${v}%`,
            background: color,
          }}
        />
      </div>
    </div>
  );
}

function MiniTrend({ sessions }) {
  const values = sessions
    .slice(0, 8)
    .reverse()
    .map((s) => Number(s.metrics?.score) || Number(s.scores?.overall) || 0);

  const max = Math.max(...values, 1);

  return (
    <div className="progress-trend">
      {values.length === 0 ? (
        <div className="progress-empty-mini">No trend data yet</div>
      ) : (
        values.map((v, i) => (
          <div key={i} className="progress-trend-bar-wrap">
            <div
              className="progress-trend-bar"
              style={{ height: `${(v / max) * 100}%` }}
              title={`${v}/100`}
            />
          </div>
        ))
      )}
    </div>
  );
}

export default function ProgressPage({ navigate, user }) {
  const [sessions, setSessions] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getSessions(20).then((data) => {
      setSessions(data);
      setLoading(false);
    });
  }, []);

  const displayName = user?.displayName || user?.email?.split("@")[0] || "User";
  const firstName = displayName.split(" ")[0];

  const totalSessions = sessions.length;

  const avg = (getter) => {
    if (!sessions.length) return 0;
    return Math.round(
      sessions.reduce((sum, s) => sum + (Number(getter(s)) || 0), 0) /
        sessions.length
    );
  };

  const avgScore = avg((s) => s.metrics?.score || s.scores?.overall);
  const avgWpm = avg((s) => s.metrics?.wpm);
  const avgFillers = avg((s) => s.metrics?.totalFillers || s.fillers?.total);
  const avgClarity = avg(
    (s) => s.metrics?.pronunciation || s.avgConfidence || s.scores?.pronunciation
  );

  const bestSession = sessions.reduce((best, current) => {
    const currentScore =
      Number(current.metrics?.score) || Number(current.scores?.overall) || 0;
    const bestScore =
      Number(best?.metrics?.score) || Number(best?.scores?.overall) || 0;

    return currentScore > bestScore ? current : best;
  }, null);

  const bestScore =
    Number(bestSession?.metrics?.score) ||
    Number(bestSession?.scores?.overall) ||
    0;

  const streakDays = [true, true, true, true, true, true, false];
  const streakCount = streakDays.filter(Boolean).length;
  const DAYS = ["M", "T", "W", "T", "F", "S", "S"];

  return (
    <div className="progress-page">
      <div className="progress-main">
        <header className="progress-topbar">
          <div>
            <h1>Your Progress</h1>
            <p>Track your speaking growth and performance over time.</p>
          </div>

          <button
            className="progress-practice-btn"
            onClick={() => navigate("practice")}
          >
            Start Practice ŌåÆ
          </button>
        </header>

        {loading ? (
          <div className="progress-loading">
            <div className="progress-spinner" />
            <p>Loading your progressŌĆ”</p>
          </div>
        ) : (
          <div className="progress-content">
            <section className="progress-hero-card">
              <div className="progress-hero-left">
                <span className="progress-pill">Progress Overview</span>
                <h2>Keep going, {firstName}! ­¤æŗ</h2>
                <p>
                  Every practice session helps you improve your clarity, pace,
                  confidence, and speaking flow.
                </p>

                <div className="progress-hero-actions">
                  <button
                    className="progress-primary-btn"
                    onClick={() => navigate("practice")}
                  >
                    Practice Again
                  </button>
                  <button
                    className="progress-outline-btn"
                    onClick={() => navigate("dashboard")}
                  >
                    Back to Home
                  </button>
                </div>
              </div>

              <div className="progress-hero-right">
                <ScoreCircle score={avgScore} />
                <p className="progress-score-caption">Average Score</p>
              </div>
            </section>

            <section className="progress-stats-grid">
              <StatCard
                icon="­¤ÄÖ’ĖÅ"
                label="Sessions"
                value={totalSessions}
                sub="completed"
                color="#7c6fcd"
              />
              <StatCard
                icon="ŌŁÉ"
                label="Best Score"
                value={bestScore}
                sub="/100"
                color="#4ecca3"
              />
              <StatCard
                icon="ŃĆ░’ĖÅ"
                label="Avg WPM"
                value={avgWpm}
                sub="speech rate"
                color="#ffd166"
              />
              <StatCard
                icon="­¤Æ¼"
                label="Avg Fillers"
                value={avgFillers}
                sub="per session"
                color="#fc6c8f"
              />
            </section>

            <section className="progress-grid-two">
              <div className="progress-card">
                <div className="progress-card-header">
                  <div>
                    <h3>Skill Breakdown</h3>
                    <p>Your average performance across major speech areas.</p>
                  </div>
                </div>

                <div className="progress-bars">
                  <ProgressBar
                    label="Pronunciation"
                    value={avgClarity}
                    color="#4ecca3"
                  />
                  <ProgressBar
                    label="Speech Pace"
                    value={avgScore}
                    color="#7c6fcd"
                  />
                  <ProgressBar
                    label="Filler Control"
                    value={Math.max(0, 100 - avgFillers * 8)}
                    color="#ffd166"
                  />
                  <ProgressBar
                    label="Speaking Flow"
                    value={avgScore}
                    color="#a99dff"
                  />
                </div>
              </div>

              <div className="progress-card">
                <div className="progress-card-header">
                  <div>
                    <h3>Weekly Streak</h3>
                    <p>Stay consistent with short daily practice.</p>
                  </div>
                </div>

                <div className="progress-streak-main">
                  <span className="progress-fire">­¤öź</span>
                  <div>
                    <h4>{streakCount} days</h4>
                    <p>Great consistency!</p>
                  </div>
                </div>

                <div className="progress-streak-days">
                  {DAYS.map((day, index) => (
                    <div key={index} className="progress-streak-day">
                      <div
                        className={`progress-streak-dot ${
                          streakDays[index] ? "done" : "empty"
                        }`}
                      >
                        {streakDays[index] && "Ō£ō"}
                      </div>
                      <span>{day}</span>
                    </div>
                  ))}
                </div>
              </div>
            </section>

            <section className="progress-grid-two">
              <div className="progress-card">
                <div className="progress-card-header">
                  <div>
                    <h3>Score Trend</h3>
                    <p>Recent performance based on saved sessions.</p>
                  </div>
                </div>

                <MiniTrend sessions={sessions} />
              </div>

              <div className="progress-card progress-best-card">
                <div className="progress-card-header">
                  <div>
                    <h3>Best Session</h3>
                    <p>Your strongest recorded performance.</p>
                  </div>
                </div>

                {bestSession ? (
                  <div className="progress-best-session">
                    <div className="progress-best-icon">­¤Åå</div>
                    <div>
                      <h4>{bestSession.scenario || "General Speaking"}</h4>
                      <p>
                        {bestSession.date
                          ? new Date(bestSession.date).toLocaleDateString(
                              "en-PH",
                              {
                                month: "long",
                                day: "numeric",
                                year: "numeric",
                              }
                            )
                          : "Recent session"}
                      </p>
                      <strong>{bestScore}/100</strong>
                    </div>
                  </div>
                ) : (
                  <div className="progress-empty-mini">
                    No best session yet. Start practicing first.
                  </div>
                )}
              </div>
            </section>

            <section className="progress-card">
              <div className="progress-card-header progress-history-header">
                <div>
                  <h3>Session History</h3>
                  <p>Review your previous speaking practice results.</p>
                </div>
              </div>

              {sessions.length === 0 ? (
                <div className="progress-empty-state">
                  <div className="progress-empty-icon">­¤ÄÖ’ĖÅ</div>
                  <h3>No saved sessions yet</h3>
                  <p>
                    Complete a recording and view your feedback to start
                    tracking progress.
                  </p>
                  <button
                    className="progress-primary-btn"
                    onClick={() => navigate("practice")}
                  >
                    Start First Practice
                  </button>
                </div>
              ) : (
                <div className="progress-session-list">
                  {sessions.map((s, index) => {
                    const score =
                      Number(s.metrics?.score) ||
                      Number(s.scores?.overall) ||
                      0;

                    const wpm = Number(s.metrics?.wpm) || 0;
                    const fillers =
                      Number(s.metrics?.totalFillers) ||
                      Number(s.fillers?.total) ||
                      0;

                    const duration = Number(s.metrics?.duration) || 0;

                    return (
                      <div key={s.id || index} className="progress-session-row">
                        <div className="progress-session-left">
                          <div className="progress-session-icon">
                            {s.scenario?.includes("Interview")
                              ? "­¤Æ╝"
                              : s.scenario?.includes("Thesis")
                              ? "­¤Äō"
                              : s.scenario?.includes("Recitation")
                              ? "­¤ō¢"
                              : "­¤Äż"}
                          </div>

                          <div>
                            <h4>{s.scenario || "General Speaking"}</h4>
                            <p>
                              {s.date
                                ? new Date(s.date).toLocaleDateString("en-PH", {
                                    month: "long",
                                    day: "numeric",
                                    year: "numeric",
                                  })
                                : "Saved session"}
                            </p>
                          </div>
                        </div>

                        <div className="progress-session-metrics">
                          <div>
                            <b>{score}</b>
                            <span>Score</span>
                          </div>
                          <div>
                            <b>{wpm}</b>
                            <span>WPM</span>
                          </div>
                          <div>
                            <b>{fillers}</b>
                            <span>Fillers</span>
                          </div>
                          <div>
                            <b>
                              {duration
                                ? `${Math.floor(duration / 60)}:${String(
                                    duration % 60
                                  ).padStart(2, "0")}`
                                : "ŌĆö"}
                            </b>
                            <span>Duration</span>
                          </div>
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </section>
          </div>
        )}
      </div>
    </div>
  );
}
